const TARGET_SELECTOR = 'div>div[mode="search-video-list"]>div[id^="grid-item-container"]'; // 目标元素选择器（可自定义）
    const DESIRED_COUNT = viewVideoCount; // 期望返回的索引数量（可自定义）
    const INDEX_RANGE = { min: 1, max: null }; // 索引范围区间（null表示使用实际最大元素数）

    function generateRandomIndexes(count, min, max) {
        const randomIndexes = [];
        const rangeSize = max - min + 1;
        const actualCount = Math.min(count, rangeSize); // 确保不超过范围大小

        if (actualCount <= 0) {
            return [];
        }

        while (randomIndexes.length < actualCount) {
            // 在[min, max]范围内生成随机数
            const random = Math.floor(Math.random() * rangeSize) + min;
            if (!randomIndexes.includes(random)) {
                randomIndexes.push(random);
            }
        }
        return randomIndexes.sort((a, b) => a - b);
    }

    try {
        // 等待目标元素加载
        async function waitForElements(selector, timeout = 8000) {
            const start = Date.now();
            while (Date.now() - start < timeout) {
                const elements = document.querySelectorAll(selector);
                if (elements.length > 0) {
                    return Array.from(elements);
                }
                await new Promise(resolve => setTimeout(resolve, 200));
            }
            throw new Error(`超时未找到目标元素: ${selector}`);
        }

        const targetItems = await waitForElements(TARGET_SELECTOR);
        const totalCount = targetItems.length;

        if (totalCount === 0) {
            console.log(`未找到匹配"${TARGET_SELECTOR}"的元素，返回空列表`);
            return [];
        }

        const actualMin = Math.max(INDEX_RANGE.min, 1); // 确保不小于1
        const actualMax = INDEX_RANGE.max !== null 
            ? Math.min(INDEX_RANGE.max, totalCount)  // 使用指定的max但不超过实际总数
            : totalCount;  // 未指定max时使用实际总数

        if (actualMin > actualMax) {
            return [];
        }

        const rangeSize = actualMax - actualMin + 1;
        const actualReturnCount = Math.min(DESIRED_COUNT, rangeSize);

        const randomIndexes = generateRandomIndexes(actualReturnCount, actualMin, actualMax);

        return randomIndexes;

    } catch (error) {
        return [];
    }

