const config = {
        targetIndex: video_list_item,
        parentSelector: 'div>div[mode="search-video-list"]>div[id^="grid-item-container"]',
        basePosition: 'center',
        randomRange: 50,
        smoothness: 800,
        wheelStepMin: 10,
        wheelStepMax: 25
    };

    try {
        const targetIndex = parseInt(config.targetIndex, 10);
        if (isNaN(targetIndex) || targetIndex < 1) throw new Error(`Invalid element index: ${config.targetIndex}`);

        const validPositions = ['top', 'center', 'bottom'];
        if (!validPositions.includes(config.basePosition)) throw new Error(`Invalid base position: ${config.basePosition}`);

        if (config.randomRange < 0) throw new Error(`Random range cannot be negative: ${config.randomRange}`);

        async function waitForElements(selector, timeout = 8000) {
            const start = Date.now();
            while (Date.now() - start < timeout) {
                const elements = document.querySelectorAll(selector);
                if (elements.length > 0) return Array.from(elements);
                await new Promise(r => setTimeout(r, 200));
            }
            throw new Error(`Timeout: Element not found - ${selector}`);
        }

        const productItems = await waitForElements(config.parentSelector);
        if (targetIndex > productItems.length) throw new Error(`Index out of range. Total elements: ${productItems.length}`);
        const targetElement = productItems[targetIndex - 1];

        const rect = targetElement.getBoundingClientRect();
        const viewportHeight = window.innerHeight;
        let baseScrollTop;
        switch(config.basePosition) {
            case 'top': baseScrollTop = window.scrollY + rect.top; break;
            case 'center': baseScrollTop = window.scrollY + rect.top + rect.height/2 - viewportHeight/2; break;
            case 'bottom': baseScrollTop = window.scrollY + rect.bottom - viewportHeight; break;
        }
        const randomOffset = (Math.random() - 0.5) * 2 * config.randomRange;
        const targetScrollTop = baseScrollTop + randomOffset;

        await smoothWheelScroll(targetScrollTop, config.smoothness, config.wheelStepMin, config.wheelStepMax);

        return true;

    } catch (error) {
        return false;
    }

    async function smoothWheelScroll(targetScrollTop, duration, stepMin, stepMax) {
        return new Promise(resolve => {
            const startScrollTop = window.scrollY;
            const distance = targetScrollTop - startScrollTop;
            const startTime = performance.now();

            function easeOutQuad(t) { return t*(2-t); }

            function animate(currentTime) {
                const elapsed = currentTime - startTime;
                const progress = Math.min(elapsed / duration, 1);
                const easedProgress = easeOutQuad(progress);
                const currentTarget = startScrollTop + distance * easedProgress;
                let delta = currentTarget - window.scrollY;

                if (Math.abs(delta) > 0) {
                    const step = Math.min(Math.max(stepMin, Math.random() * stepMax), Math.abs(delta));
                    const wheelDelta = delta > 0 ? step : -step;

                    const evt = new WheelEvent('wheel', {bubbles:true, deltaY: wheelDelta});
                    window.dispatchEvent(evt);

                    window.scrollBy(0, wheelDelta);
                }

                if (progress < 1) {
                    requestAnimationFrame(animate);
                } else {
                    resolve();
                }
            }
            requestAnimationFrame(animate);
        });
    }

