const commentContainer = document.querySelector('div[data-e2e="search-comment-container"] > div');
    if (!commentContainer) return;

    const MIN_TOTAL_SCROLL = 500;
    const MAX_TOTAL_SCROLL = 1000;
    const MIN_SEGMENT = 100;
    const MAX_SEGMENT = 300;
    const SEGMENT_DURATION = 400;
    const RANDOM_PAUSE_CHANCE = 0.1;
    const MIN_PAUSE = 150;
    const MAX_PAUSE = 500;
    const RANDOM_BACK_CHANCE = 0.05;
    const MAX_BACK_STEP = 15;

    const TOTAL_SCROLL = Math.random() * (MAX_TOTAL_SCROLL - MIN_TOTAL_SCROLL) + MIN_TOTAL_SCROLL;
    let scrolled = 0;

    function simulateMouseMove(element) {
        const rect = element.getBoundingClientRect();
        const x = rect.left + Math.random() * rect.width;
        const y = rect.top + Math.random() * rect.height;
        element.dispatchEvent(new MouseEvent('mousemove', { bubbles: true, clientX: x, clientY: y }));
    }

    function easeInOutCubic(t) {
        return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
    }

    function scrollSegment(distance, duration) {
        return new Promise(resolve => {
            const startScrollTop = commentContainer.scrollTop;
            const startTime = performance.now();

            function step(currentTime) {
                const elapsed = currentTime - startTime;
                let t = Math.min(elapsed / duration, 1);
                let target = distance * easeInOutCubic(t);

                if (Math.random() < RANDOM_BACK_CHANCE) target -= Math.random() * MAX_BACK_STEP;

                const delta = target - (commentContainer.scrollTop - startScrollTop);
                commentContainer.scrollBy(0, delta);
                commentContainer.dispatchEvent(new Event('scroll', { bubbles: true }));
                simulateMouseMove(commentContainer);

                if (t < 1 && commentContainer.scrollTop + commentContainer.clientHeight < commentContainer.scrollHeight) {
                    requestAnimationFrame(step);
                } else {
                    resolve();
                }
            }
            requestAnimationFrame(step);
        });
    }

    while (scrolled < TOTAL_SCROLL && commentContainer.scrollTop + commentContainer.clientHeight < commentContainer.scrollHeight) {
        const remaining = TOTAL_SCROLL - scrolled;
        const segment = Math.min(Math.random() * (MAX_SEGMENT - MIN_SEGMENT) + MIN_SEGMENT, remaining);

        await scrollSegment(segment, SEGMENT_DURATION);
        scrolled += segment;

        if (Math.random() < RANDOM_PAUSE_CHANCE) {
            const pauseTime = MIN_PAUSE + Math.random() * (MAX_PAUSE - MIN_PAUSE);
            await new Promise(resolve => setTimeout(resolve, pauseTime));
        }
    }

