const CLICK_DELAY_RANGE = [200, 800];

function randomDelay() {
  const [min, max] = CLICK_DELAY_RANGE;
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function sleep(ms) {
  return new Promise(r => setTimeout(r, ms));
}

function isInViewport(el) {
  const rect = el.getBoundingClientRect();
  return rect.top >= 0 && rect.bottom <= window.innerHeight;
}

async function waitForStable(el, timeout = 1500) {
  let lastTop = el.getBoundingClientRect().top;
  let stableCount = 0;
  const start = Date.now();

  while (Date.now() - start < timeout) {

    await new Promise(requestAnimationFrame);

    const nowTop = el.getBoundingClientRect().top;

    if (Math.abs(nowTop - lastTop) < 1) {
      stableCount++;
      if (stableCount >= 3) return true;
    } else {
      stableCount = 0;
    }

    lastTop = nowTop;
  }

  return false;
}

const buttons = document.querySelectorAll('div[aria-pressed]');
const candidates = [];

for (const btn of buttons) {

  if (!btn.querySelector('svg')) continue;

  if (btn.getAttribute("aria-pressed") === "true") continue;

  if (!isInViewport(btn)) continue;

  candidates.push(btn);
}

if (candidates.length === 0) {
  return;
}

const target = candidates[Math.floor(Math.random() * candidates.length)];

target.scrollIntoView({
  block: "center"
});

await waitForStable(target);

await sleep(randomDelay());

target.click();

