const config = {
        distanceRange: [1500, 2800],     // 总滚动距离区间
        direction: 'down',               // 'down' 或 'up'
        stepRatioRange: [0.1, 0.3],      // 碎步比例范围（每次滚动占总距离的比例）
        stepDurationRange: [500, 1200],  // 每步之间的等待时间（毫秒）
    };

    const wait = ms => new Promise(resolve => setTimeout(resolve, ms));
    const randomInRange = (min, max) => Math.random() * (max - min) + min;

    // 当前滚动位置
    let scrollTop = window.pageYOffset || document.documentElement.scrollTop;

    // 随机生成总滚动距离
    const totalDistance = Math.floor(randomInRange(config.distanceRange[0], config.distanceRange[1]));

    let remaining = totalDistance;
    let steps = [];

    // 按比例拆分成多个小碎步
    while (remaining > 0) {
        let ratio = randomInRange(config.stepRatioRange[0], config.stepRatioRange[1]);
        let step = Math.floor(totalDistance * ratio);

        // 防止超过剩余距离
        if (step > remaining) step = remaining;

        steps.push(step);
        remaining -= step;
    }

    // 执行小碎步滚动
    for (let step of steps) {
        const nextScroll = config.direction === 'up'
            ? Math.max(scrollTop - step, 0)
            : scrollTop + step;

        window.scrollTo({ top: nextScroll, behavior: 'smooth' });

        // 等待随机时间
        const waitTime = Math.floor(randomInRange(config.stepDurationRange[0], config.stepDurationRange[1]));
        await wait(waitTime);

        scrollTop = nextScroll;
    }

    return {
        success: true,
        steps: steps,
        totalDistance: totalDistance,
        finalScroll: scrollTop
    };

// 概率阈值（0-1之间，值越大，返回"true"的概率越高）
    const trueProbability = 0.8; // 例如：0.6表示60%概率返回"true"

    return Math.random() < trueProbability ? "true" : "false";

// 配置变量 - 可根据需求修改
const visibilityThreshold = 20; // 可见性阈值百分比
const fullVisibilityTolerance = 2; // 100%可见性容差(像素)
const containerSelector = 'div > article'; // 容器元素选择器（父元素）
// 需要高亮的元素选择器（相对于容器内部）
const highlightElementSelector = 'article > div'; // 帖子边框元素
// 高亮样式配置
const highlightStyle = {
    border: '3px solid orange',
    borderRadius: '4px',
    transition: 'all 0.3s ease'
};
// 目标子元素选择器：明确区分点赞/未点赞状态
const targetChildSelectors = {
    unliked: 'svg[aria-label="Like"]',      // 未点赞状态元素（点击目标）
    liked: 'svg[aria-label="Unlike"]'       // 已点赞状态元素
};
// 滚动和等待配置
const scrollDuration = 600; // 顺滑滚动持续时间(毫秒)
const scrollEasing = 'ease-in-out'; // 滚动缓动函数
// const postScrollWaitTime = 500; // 滚动后固定等待时长(毫秒)
// 如需随机等待时间范围，可启用下面两个变量并注释上面的固定等待变量
const postScrollWaitMin = 1000; // 滚动后最小等待时长(毫秒)
const postScrollWaitMax = 1500; // 滚动后最大等待时长(毫秒)

try {
    // 等待 DOM 就绪
    await new Promise(resolve => {
        if (document.readyState === 'complete' || document.readyState === 'interactive') {
            resolve();
        } else {
            document.addEventListener('DOMContentLoaded', resolve, { once: true });
        }
    });

    // 步骤 1: 获取所有容器元素
    const containerElements = Array.from(document.querySelectorAll(containerSelector));
    if (containerElements.length === 0) {
        throw new Error(`没有找到匹配容器选择器的元素: ${containerSelector}`);
    }

    // 步骤 2: 计算所有容器的可见性并分类
    const allContainers = [];
    const windowHeight = window.innerHeight || document.documentElement.clientHeight;
    const windowWidth = window.innerWidth || document.documentElement.clientWidth;

    containerElements.forEach((container, index) => {
        const rect = container.getBoundingClientRect();
        const elementArea = rect.width * rect.height;

        if (elementArea === 0) return; // 跳过无尺寸的元素

