// 顺滑滚动到页面中间的函数
function smoothScrollToCenter(element) {
    return new Promise(resolve => {
        // 获取元素位置信息
        const elementRect = element.getBoundingClientRect();
        const elementTop = elementRect.top + window.pageYOffset;
        const windowHeight = window.innerHeight || document.documentElement.clientHeight;
        const targetScrollTop = elementTop - (windowHeight / 2) + (elementRect.height / 2);

        // 获取当前滚动位置
        const startScrollTop = window.pageYOffset || document.documentElement.scrollTop;
        const distance = targetScrollTop - startScrollTop;

        // 如果已经在目标位置附近，直接 resolve
        if (Math.abs(distance) < 5) {
            resolve();
            return;
        }

        const startTime = performance.now();

        // 缓动函数 - 实现平滑的加速减速效果
        const easeFunction = (t) => {
            switch (scrollEasing) {
                case 'ease-in':
                    return t * t; // 先慢后快
                case 'ease-out':
                    return t * (2 - t); // 先快后慢
                case 'ease-in-out':
                default:
                    return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2; // 先慢中快后慢
            }
        };

        // 滚动动画函数
        const animateScroll = (currentTime) => {
            const elapsedTime = currentTime - startTime;
            const progress = Math.min(elapsedTime / scrollDuration, 1);
            const easedProgress = easeFunction(progress);

            window.scrollTo(0, startScrollTop + distance * easedProgress);

            if (progress < 1) {
                requestAnimationFrame(animateScroll);
            } else {
                // 动画结束后确保精确定位
                window.scrollTo(0, targetScrollTop);
                resolve();
            }
        };

        // 开始滚动动画
        requestAnimationFrame(animateScroll);
    });
}

