// 可见性阈值设置
    const visibilityThreshold = 100; // 可见性阈值百分比
    const fullVisibilityTolerance = 2; // 100%可见性容差（像素）

    // 点击指示器设置
    const enableClickIndicator = true; // 启用点击指示器边框
    const indicatorDisplayTime = 600; // 边框显示时长（毫秒）

    // 目标元素选择器
    const selector = 'main[id="main-content"] > div > search-telemetry-tracker';

    try {
        // 等待DOM加载完成
        await new Promise(resolve => {
            if (document.readyState === 'complete' || document.readyState === 'interactive') {
                resolve();
            } else {
                document.addEventListener('DOMContentLoaded', resolve, { once: true });
            }
        });

        // 第一步：获取可见元素索引
        const elements = Array.from(document.querySelectorAll(selector));
        if (elements.length === 0) {
            throw new Error("未找到匹配选择器的元素");
        }

        const visibleIndices = [];
        const windowHeight = window.innerHeight || document.documentElement.clientHeight;
        const windowWidth = window.innerWidth || document.documentElement.clientWidth;

        // 检查元素可见性
        elements.forEach((el, index) => {
            const rect = el.getBoundingClientRect();
            const elementArea = rect.width * rect.height;

            if (elementArea === 0) return;

            // 计算可见区域
            const visibleLeft = Math.max(0, rect.left);
            const visibleTop = Math.max(0, rect.top);
            const visibleRight = Math.min(rect.right, windowWidth);
            const visibleBottom = Math.min(rect.bottom, windowHeight);

            // 计算可见百分比
            const visibleArea = (visibleRight - visibleLeft) * (visibleBottom - visibleTop);
            const visibilityPercentage = Math.round((visibleArea / elementArea) * 10000) / 100;

            // 检查可见性条件
            let isVisible = false;
            if (visibilityThreshold === 100) {
                // 处理100%可见性（带容差）
                const isLeftInView = rect.left >= -fullVisibilityTolerance;
                const isRightInView = rect.right <= windowWidth + fullVisibilityTolerance;
                const isTopInView = rect.top >= -fullVisibilityTolerance;
                const isBottomInView = rect.bottom <= windowHeight + fullVisibilityTolerance;
                isVisible = isLeftInView && isRightInView && isTopInView && isBottomInView;
            } else {
                isVisible = visibilityPercentage > visibilityThreshold;
            }

            if (isVisible) {
                visibleIndices.push(index);
                console.log(`元素 ${index} 可见性: ${visibilityPercentage}% - 可见`);
            }
        });

        if (visibleIndices.length === 0) {
            throw new Error(`没有元素达到可见性阈值(${visibilityThreshold}%)`);
        }
        console.log(`找到 ${visibleIndices.length} 个可见元素`);

        // 第二步：从可见元素中随机选择
        const randomIndex = visibleIndices[Math.floor(Math.random() * visibleIndices.length)];
        console.log(`随机可见元素索引: ${randomIndex}`);

        // 第三步：点击选中的元素
        const containerElement = elements[randomIndex];

        // 滚动到元素位置
        containerElement.scrollIntoView({
            behavior: 'auto',
            block: 'nearest'
        });
        await new Promise(resolve => setTimeout(resolve, 300));

        // 查找可点击的子元素
        const clickableSelectors = ['a', 'button', '[onclick]', '[role="button"]', '.clickable', '.btn'];
        let targetElement = null;
        for (const sel of clickableSelectors) {
            const candidate = containerElement.querySelector(sel);
            if (candidate) {
                targetElement = candidate;
                break;
            }
        }
        if (!targetElement) {
            targetElement = containerElement; // 如果没有找到子元素则点击容器
        }

        // 保存原始样式用于恢复
        const originalBorder = targetElement.style.border;
        const originalBoxShadow = targetElement.style.boxShadow;
        const originalTransition = targetElement.style.transition;

        // 准备点击事件
        const rect = targetElement.getBoundingClientRect();
        const centerX = rect.left + rect.width / 2;
        const centerY = rect.top + rect.height / 2;

        const createEvent = (type) => new MouseEvent(type, {
            bubbles: true,
            cancelable: true,
            view: window,
            clientX: centerX,
            clientY: centerY,
            button: 0,
            buttons: 1
        });

        const events = [
            createEvent('mouseover'),
            createEvent('mousemove'),
            createEvent('mousedown'),
            createEvent('mouseup'),
            createEvent('click')
        ];

        // 跟踪点击是否成功
        let isClickSuccessful = false;
        const originalDispatch = targetElement.dispatchEvent;
        targetElement.dispatchEvent = function(event) {
            const result = originalDispatch.call(this, event);
            if (event.type === 'click') {
                isClickSuccessful = result;
            }
            return result;
        };

        // 触发事件序列
        for (const [i, event] of events.entries()) {
            targetElement.dispatchEvent(event);
            if (i < events.length - 1) {
                await new Promise(resolve => setTimeout(resolve, 50));
            }
        }

        // 恢复原始方法
        targetElement.dispatchEvent = originalDispatch;

        // 尝试直接调用onclick
        if (typeof targetElement.onclick === 'function') {
            try {
                targetElement.onclick();
                isClickSuccessful = true;
            } catch (e) { /* 忽略错误 */ }
        }

        // 显示点击指示器
        if (enableClickIndicator && isClickSuccessful) {
            targetElement.style.transition = 'all 0.2s ease-in-out';
            targetElement.style.border = '4px solid #ff7a00';
            targetElement.style.boxShadow = '0 0 0 2px rgba(255, 122, 0, 0.3)';

            // 恢复原始样式
            await new Promise(resolve => setTimeout(resolve, indicatorDisplayTime));
            targetElement.style.border = originalBorder;
            targetElement.style.boxShadow = originalBoxShadow;
            targetElement.style.transition = originalTransition;
        }

        if (isClickSuccessful) {
            console.log(`成功点击随机可见元素（索引: ${randomIndex}）`);
            return {
                success: true,
                message: `点击了随机可见元素（索引: ${randomIndex}）`,
                index: randomIndex
            };
        } else {
            throw new Error("元素点击事件被阻止或无效");
        }

    } catch (error) {
        console.error("操作失败:", error.message);
        return { success: false, message: error.message };
    }

