            clientX: centerX,
            clientY: centerY,
            button: 0,
            buttons: 1
        });

        const events = [
            createEvent('mouseover'),
            createEvent('mousemove'),
            createEvent('mousedown'),
            createEvent('mouseup'),
            createEvent('click')
        ];

        // 跟踪点击是否成功
        let isClickSuccessful = false;
        const originalDispatch = targetElement.dispatchEvent;
        targetElement.dispatchEvent = function(event) {
            const result = originalDispatch.call(this, event);
            if (event.type === 'click') {
                isClickSuccessful = result;
            }
            return result;
        };

        // 触发事件序列
        for (const [i, event] of events.entries()) {
            targetElement.dispatchEvent(event);
            if (i < events.length - 1) {
                await new Promise(resolve => setTimeout(resolve, 50));
            }
        }

        // 恢复原始方法
        targetElement.dispatchEvent = originalDispatch;

        // 尝试直接调用onclick
        if (typeof targetElement.onclick === 'function') {
            try {
                targetElement.onclick();
                isClickSuccessful = true;
            } catch (e) { /* 忽略错误 */ }
        }

        // 显示点击指示器
        if (enableClickIndicator && isClickSuccessful) {
            targetElement.style.transition = 'all 0.2s ease-in-out';
            targetElement.style.border = '4px solid #ff7a00';
            targetElement.style.boxShadow = '0 0 0 2px rgba(255, 122, 0, 0.3)';

            // 恢复原始样式
            await new Promise(resolve => setTimeout(resolve, indicatorDisplayTime));
            targetElement.style.border = originalBorder;
            targetElement.style.boxShadow = originalBoxShadow;
            targetElement.style.transition = originalTransition;
        }

        if (isClickSuccessful) {
            console.log(`成功点击随机可见元素（索引: ${randomIndex}）`);
            return {
                success: true,
                message: `点击了随机可见元素（索引: ${randomIndex}）`,
                index: randomIndex
            };
        } else {
            throw new Error("元素点击事件被阻止或无效");
        }

    } catch (error) {
        console.error("操作失败:", error.message);
        return { success: false, message: error.message };
    }

