    distanceMax: 1500,             // 最大滚动距离（像素）
    direction: 'down',             // 滚动方向：'down' 或 'up'

    // 通用滚动参数
    minStepDuration: 500,          // 最小间隔时间（毫秒）
    maxStepDuration: 1200,         // 最大间隔时间（毫秒）
    maxStepDistance: 500,          // 最大步长（像素）
    minStepDistance: 100,          // 最小步长（像素）

    // 往回滚设置
    enableBackstep: true,          // 往回滚开关
    backStepRatio: 0.3,            // 往回滚比例（前一步的百分比）
    backStepChance: 0.2,           // 往回滚概率（0-1之间）
    randomFactor: 0.3,             // 随机调整因子

    // 懒加载优化参数
    lazyLoadWaitTime: 2000,        // 懒加载内容等待时间（毫秒）
    heightChangeTolerance: 50,     // 高度变化容忍值（像素）
    maxHeightCheckRetries: 3       // 最大高度检查重试次数
};

// 生成范围内的随机数
const randomInRange = (min, max) => {
    return Math.floor(Math.random() * (max - min + 1)) + min;
};

// 封装setTimeout为Promise
const wait = (ms) => new Promise(resolve => setTimeout(resolve, ms));

// 获取动态更新的页面高度
const getCurrentPageHeight = () => {
    return Math.max(
        document.body.scrollHeight,
        document.body.offsetHeight,
        document.documentElement.clientHeight,
        document.documentElement.scrollHeight,
        document.documentElement.offsetHeight
    );
};

// 等待懒加载内容完成加载
const waitForLazyLoad = async (currentScrollTop) => {
    let previousHeight = getCurrentPageHeight();
    let retries = 0;

    // 滚动到当前位置以触发懒加载
    window.scrollTo({ top: currentScrollTop, behavior: 'auto' });
    await wait(config.lazyLoadWaitTime);

    // 检查高度变化，确认懒加载完成
    while (retries < config.maxHeightCheckRetries) {
        const newHeight = getCurrentPageHeight();
        if (Math.abs(newHeight - previousHeight) <= config.heightChangeTolerance) {
            break; // 高度稳定，懒加载完成
        }

        previousHeight = newHeight;
        retries++;
        await wait(config.lazyLoadWaitTime); // 等待更多内容加载
    }

    return {
        height: previousHeight,
        retries: retries
    };
};

// 快速回滚到顶部的函数
const quickReturnToTop = async () => {
    const currentScrollTop = window.pageYOffset || document.documentElement.scrollTop;

    // 如果当前位置已经在顶部附近，则不需要回滚
    if (currentScrollTop <= config.topReturnThreshold) {
        return currentScrollTop;
    }

    // 执行回滚到顶部
    window.scrollTo({ top: 0, behavior: config.topReturnBehavior });

    // 等待回滚完成
    await wait(config.topReturnWaitTime);

    // 确认已到达顶部
    const newScrollTop = window.pageYOffset || document.documentElement.scrollTop;

    return newScrollTop;
};

// 初始化页面信息
const windowHeight = window.innerHeight;
let startScrollTop = window.pageYOffset || document.documentElement.scrollTop;

// 新增：如果启用了顶部回滚且初始位置不在顶部，则先回滚到顶部
if (config.enableQuickReturnToTop) {
    startScrollTop = await quickReturnToTop();
}

// 等待初始懒加载内容
const initialLoadResult = await waitForLazyLoad(startScrollTop);
let documentHeight = initialLoadResult.height;
let scrollableHeight = documentHeight - windowHeight;

let lastStepDistance = 0;        // 记录上一步滚动距离
let totalScrolled = 0;           // 记录总滚动距离
let targetScrollTop;             // 目标滚动位置

try {
    // 根据滚动逻辑计算初始目标位置
    if (config.scrollLogic === 'target-position') {
        switch(config.targetPosition) {
            case 'top':
                targetScrollTop = 0;
                break;
            case 'middle':
                targetScrollTop = Math.max(0, Math.floor(scrollableHeight / 2));
                break;
            case 'bottom':
                targetScrollTop = Math.max(0, scrollableHeight - 10);
                break;
            default:
                targetScrollTop = Math.max(0, Math.min(Number(config.targetPosition) || 0, scrollableHeight));
        }
    } else {
        const randomDistance = randomInRange(config.distanceMin, config.distanceMax);
        const actualDistance = config.direction === 'up' 
            ? -Math.abs(randomDistance) 
            : Math.abs(randomDistance);
        targetScrollTop = Math.max(0, Math.min(startScrollTop + actualDistance, scrollableHeight));
    }

    // 循环执行滚动步骤
    while (true) {
        const currentScrollTop = window.pageYOffset || document.documentElement.scrollTop;

        // 每次循环都更新页面高度（应对懒加载）
        documentHeight = getCurrentPageHeight();
        scrollableHeight = documentHeight - windowHeight;

        // 如果是滚动到底部模式，动态更新目标位置
        if (config.scrollLogic === 'target-position' && config.targetPosition === 'bottom') {
            targetScrollTop = Math.max(0, scrollableHeight - 10);
        }

        // 计算剩余距离
        const remainingDistance = targetScrollTop - currentScrollTop;

        // 检查是否到达目标
        if (Math.abs(remainingDistance) <= config.targetTolerance) {
            // 最终精确定位
            window.scrollTo({ top: targetScrollTop, behavior: 'auto' });
            break;
        }

        // 如果剩余距离过大，可能是因为新内容加载，重新评估目标
        if (Math.abs(remainingDistance) > scrollableHeight * 0.5) {
            if (config.scrollLogic === 'pixel-distance') {
                const remainingDistanceNeeded = targetScrollTop - startScrollTop;
                targetScrollTop = Math.max(0, Math.min(startScrollTop + remainingDistanceNeeded, scrollableHeight));
            }
        }

        // 决定是否往回滚（仅当启用时）
        let isBackStep = false;
        if (config.enableBackstep && Math.abs(lastStepDistance) > 0 && Math.random() < config.backStepChance) {
            isBackStep = true;
        }

        // 计算当前步长
        let stepDistance;
        if (isBackStep) {
            // 往回滚动
            stepDistance = -lastStepDistance * config.backStepRatio;
        } else {
            // 向前滚动
            let baseStep = remainingDistance;

            // 限制步长在最大最小范围内
            if (Math.abs(baseStep) > config.maxStepDistance) {
                baseStep = baseStep > 0 ? config.maxStepDistance : -config.maxStepDistance;
            } else if (Math.abs(baseStep) < config.minStepDistance) {
                baseStep = baseStep > 0 ? config.minStepDistance : -config.minStepDistance;
            }

            // 添加随机调整
            const randomAdjustment = baseStep * config.randomFactor * (Math.random() * 2 - 1);
            stepDistance = baseStep + randomAdjustment;

            // 再次确保步长在有效范围内
            if (stepDistance > 0) {
                stepDistance = Math.min(config.maxStepDistance, Math.max(config.minStepDistance, stepDistance));
            } else {
                stepDistance = Math.max(-config.maxStepDistance, Math.min(-config.minStepDistance, stepDistance));
            }

            // 保存当前步长用于可能的往回滚
            lastStepDistance = stepDistance;
        }

        // 随机生成当前步的等待时间
        const stepDuration = randomInRange(config.minStepDuration, config.maxStepDuration);

        // 执行滚动
        window.scrollBy({ top: stepDistance, behavior: config.scrollType });

        // 更新总滚动距离
        totalScrolled += Math.abs(stepDistance);

        // 等待步骤完成，同时给懒加载内容留出时间
        await wait(stepDuration);

        // 在滚动后检查并等待懒加载完成
        if (stepDistance > 0) { // 只有向下滚动时才需要等待懒加载
            const newScrollTop = window.pageYOffset || document.documentElement.scrollTop;
            await waitForLazyLoad(newScrollTop);
        }
    }
} catch (error) {
    return {
        success: false,
        error: error.message,
        totalScrolled: totalScrolled
    };
}

