// 核心配置 - 可视区阈值可调（百分比，如1表示1%可见即算可视）
const visibilityThreshold = 1; // 可调整的可视区阈值
const NO_ELEMENT_INDEX = -1;

// 点击指示器设置
const enableClickIndicator = false; // 启用点击指示器
const indicatorDisplayTime = 600; // 指示器显示时间(毫秒)

// 目标元素选择器
const selector = 'shreddit-feed[navigation-session-id] shreddit-post';

// 滚动配置
const scrollToElementBehavior = 'smooth';
const scrollWaitTime = 500;

try {
    // 等待DOM加载完成
    await new Promise(resolve => {
        if (document.readyState === 'complete' || document.readyState === 'interactive') {
            resolve();
        } else {
            document.addEventListener('DOMContentLoaded', resolve, { once: true });
        }
    });

    // 提取评论数
    function getCommentCount(postElement) {
        try {
            if (!postElement.shadowRoot) return 0;

            // 从faceplate-number提取
            const faceplateNumbers = postElement.shadowRoot.querySelectorAll('faceplate-number');
            if (faceplateNumbers.length > 0) {
                const commentNumberEl = faceplateNumbers[1] || faceplateNumbers[0];
                if (commentNumberEl) {
                    // 优先获取number属性
                    const numberAttr = commentNumberEl.getAttribute('number');
                    if (numberAttr) return parseCommentCount(numberAttr);

                    // 从内容提取
                    const numberText = commentNumberEl.shadowRoot 
                        ? commentNumberEl.shadowRoot.textContent.trim()
                        : commentNumberEl.textContent.trim();
                    return parseCommentCount(numberText);
                }
            }

            // 从action-row提取
            const actionRow = postElement.shadowRoot.querySelector('[data-testid="action-row"]');
            if (actionRow) {
                const commentText = Array.from(actionRow.querySelectorAll('*'))
                    .find(el => el.textContent.toLowerCase().includes('comment'))?.textContent;
                if (commentText) return parseCommentCount(commentText);
            }

            return 0;
        } catch (error) {
            return 0;
        }
    }

    // 解析评论数
    function parseCommentCount(text) {
        if (!text) return 0;
        const numericText = text.replace(/[^0-9]/g, '');
        return numericText ? parseInt(numericText, 10) : 0;
    }

    // 获取所有元素
    const elements = Array.from(document.querySelectorAll(selector));
    if (elements.length === 0) {
        return {
            click_status: false,
            message: "未找到匹配的元素",
            index: NO_ELEMENT_INDEX
        };
    }

    // 收集可视元素信息
    const visibilityInfo = [];
    const windowHeight = window.innerHeight || document.documentElement.clientHeight;
    const windowWidth = window.innerWidth || document.documentElement.clientWidth;

    elements.forEach((postElement, index) => {
        const linkElement = postElement.querySelector('a[data-ks-id]') || postElement;
        const rect = postElement.getBoundingClientRect();
        const elementArea = rect.width * rect.height;

        // 计算可见区域
        const visibleLeft = Math.max(0, rect.left);
        const visibleTop = Math.max(0, rect.top);
        const visibleRight = Math.min(rect.right, windowWidth);
        const visibleBottom = Math.min(rect.bottom, windowHeight);
        const visibleArea = (visibleRight - visibleLeft) * (visibleBottom - visibleTop);
        const visibilityPercentage = elementArea > 0 
            ? Math.round((visibleArea / elementArea) * 10000) / 100 
            : 0;

        // 检查可视性（基于可调阈值）
        const isVisible = Math.max(0, visibilityPercentage) >= visibilityThreshold;

        if (isVisible) {
            visibilityInfo.push({
                element: linkElement,
                index: index,
                commentCount: getCommentCount(postElement),
                visibilityPercentage: visibilityPercentage
            });
        }
    });

    // 无可见元素
    if (visibilityInfo.length === 0) {
        return {
            click_status: false,
            message: `没有符合可视阈值(${visibilityThreshold}%)的元素`,
            index: NO_ELEMENT_INDEX
        };
    }

    // 找到可视区中评论数最大的元素
    const targetInfo = visibilityInfo.sort((a, b) => b.commentCount - a.commentCount)[0];

    // 滚动到目标元素
    targetInfo.element.scrollIntoView({
        behavior: scrollToElementBehavior,
        block: 'center',
        inline: 'center'
    });
    await new Promise(resolve => setTimeout(resolve, scrollWaitTime));

    // 查找可点击目标
    const clickableSelectors = [
        'a[href]', 
        'button:not([disabled])', 
        '[onclick]', 
        '[role="button"]:not([aria-disabled="true"])', 
        '.clickable', 
        '.btn:not([disabled])'
    ];

    let clickTarget = null;
    for (const sel of clickableSelectors) {
        const candidate = targetInfo.element.querySelector(sel);
        if (candidate) {
            clickTarget = candidate;
            break;
        }
    }
    if (!clickTarget) clickTarget = targetInfo.element;

    // 保存原始样式用于恢复
    const originalBorder = clickTarget.style.border;
    const originalBoxShadow = clickTarget.style.boxShadow;
    const originalTransition = clickTarget.style.transition;

    // 执行点击
    const rect = clickTarget.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;

    const createEvent = (type) => new MouseEvent(type, {
        bubbles: true,
        cancelable: true,
        view: window,
        clientX: centerX,
        clientY: centerY,
        button: 0,
        buttons: 1
    });

    const events = ['mouseover', 'mousemove', 'mousedown', 'mouseup', 'click']
        .map(type => createEvent(type));

    let isClickSuccessful = false;
    const originalDispatch = clickTarget.dispatchEvent;
    clickTarget.dispatchEvent = function(event) {
        const result = originalDispatch.call(this, event);
        if (event.type === 'click') isClickSuccessful = result;
        return result;
    };

    // 触发事件序列
    for (const [i, event] of events.entries()) {
        clickTarget.dispatchEvent(event);
        if (i < events.length - 1) {
            await new Promise(resolve => setTimeout(resolve, Math.floor(Math.random() * 50) + 30));
        }
    }
    clickTarget.dispatchEvent = originalDispatch;

    // 备选点击方式
    if (typeof clickTarget.onclick === 'function') {
        try {
            clickTarget.onclick();
            isClickSuccessful = true;
        } catch (e) { /* 忽略点击异常 */ }
    }

    // 显示橙色提示边框
    if (enableClickIndicator && isClickSuccessful) {
        clickTarget.style.transition = 'all 0.2s ease-in-out';
        clickTarget.style.border = '4px solid #ff7a00'; // 橙色边框
        clickTarget.style.boxShadow = '0 0 0 2px rgba(255, 122, 0, 0.3)'; // 橙色阴影
        await new Promise(resolve => setTimeout(resolve, indicatorDisplayTime));
        // 恢复原始样式
        clickTarget.style.border = originalBorder;
        clickTarget.style.boxShadow = originalBoxShadow;
        clickTarget.style.transition = originalTransition;
    }

    return {
        click_status: isClickSuccessful,
        message: isClickSuccessful 
            ? `已点击可视区最大评论数元素(索引: ${targetInfo.index}, 评论数: ${targetInfo.commentCount}, 可见度: ${targetInfo.visibilityPercentage}%)` 
            : `点击失败(索引: ${targetInfo.index})`,
        index: targetInfo.index,
        maxCommentCount: targetInfo.commentCount,
        visibilityThreshold: visibilityThreshold
    };

} catch (error) {
    return {
        click_status: false,
        message: `操作失败: ${error.message}`,
        index: NO_ELEMENT_INDEX
    };
}

