// 可见性阈值设置（只要有1%可见就算可视）
const visibilityThreshold = 1; 

// 目标元素选择器
const selector = 'shreddit-feed[navigation-session-id] shreddit-post';

try {
    // 等待DOM加载完成
    await new Promise(resolve => {
        if (document.readyState === 'complete' || document.readyState === 'interactive') {
            resolve();
        } else {
            document.addEventListener('DOMContentLoaded', resolve, { once: true });
        }
    });

    // 提取评论数
    function getCommentCount(postElement) {
        try {
            if (!postElement.shadowRoot) {
                return 0;
            }

            // 从faceplate-number提取
            const faceplateNumbers = postElement.shadowRoot.querySelectorAll('faceplate-number');
            if (faceplateNumbers.length > 0) {
                const commentNumberEl = faceplateNumbers[1] || faceplateNumbers[0];
                if (commentNumberEl) {
                    // 优先获取number属性
                    const numberAttr = commentNumberEl.getAttribute('number');
                    if (numberAttr) {
                        return parseCommentCount(numberAttr);
                    }

                    // 从内容提取
                    const numberText = commentNumberEl.shadowRoot 
                        ? commentNumberEl.shadowRoot.textContent.trim()
                        : commentNumberEl.textContent.trim();
                    return parseCommentCount(numberText);
                }
            }

            // 从action-row提取
            const actionRow = postElement.shadowRoot.querySelector('[data-testid="action-row"]');
            if (actionRow) {
                const commentText = Array.from(actionRow.querySelectorAll('*'))
                    .find(el => el.textContent.toLowerCase().includes('comment'))?.textContent;
                if (commentText) {
                    return parseCommentCount(commentText);
                }
            }

            return 0;
        } catch (error) {
            return 0;
        }
    }

    // 解析评论数
    function parseCommentCount(text) {
        if (!text) return 0;
        const numericText = text.replace(/[^0-9]/g, '');
        return numericText ? parseInt(numericText, 10) : 0;
    }

    // 获取所有元素
    const elements = Array.from(document.querySelectorAll(selector));
    if (elements.length === 0) {
        return { maxCommentCount: 0 };
    }

    // 计算可见元素及其评论数
    let maxCommentCount = 0;
    const windowHeight = window.innerHeight || document.documentElement.clientHeight;
    const windowWidth = window.innerWidth || document.documentElement.clientWidth;

    elements.forEach(postElement => {
        const rect = postElement.getBoundingClientRect();
        const elementArea = rect.width * rect.height;

        // 计算可见区域
        const visibleLeft = Math.max(0, rect.left);
        const visibleTop = Math.max(0, rect.top);
        const visibleRight = Math.min(rect.right, windowWidth);
        const visibleBottom = Math.min(rect.bottom, windowHeight);
        const visibleArea = (visibleRight - visibleLeft) * (visibleBottom - visibleTop);
        const visibilityPercentage = elementArea > 0 
            ? Math.round((visibleArea / elementArea) * 10000) / 100 
            : 0;

        // 检查可见性（≥1%即算可视）
        const isVisible = Math.max(0, visibilityPercentage) >= visibilityThreshold;

        if (isVisible) {
            const commentCount = getCommentCount(postElement);
            if (commentCount > maxCommentCount) {
                maxCommentCount = commentCount;
            }
        }
    });

    // 仅返回最大评论数
    return maxCommentCount ;

} catch (error) {
    return 0;
}

