    // 解析评论数
    function parseCommentCount(text) {
        if (!text) return 0;
        const numericText = text.replace(/[^0-9]/g, '');
        return numericText ? parseInt(numericText, 10) : 0;
    }

    // 获取所有元素
    const elements = Array.from(document.querySelectorAll(selector));
    if (elements.length === 0) {
        return {
            click_status: false,
            message: "未找到匹配的元素",
            index: NO_ELEMENT_INDEX
        };
    }

    // 收集可视元素信息
    const visibilityInfo = [];
    const windowHeight = window.innerHeight || document.documentElement.clientHeight;
    const windowWidth = window.innerWidth || document.documentElement.clientWidth;

    elements.forEach((postElement, index) => {
        const linkElement = postElement.querySelector('a[data-ks-id]') || postElement;
        const rect = postElement.getBoundingClientRect();
        const elementArea = rect.width * rect.height;

        // 计算可见区域
        const visibleLeft = Math.max(0, rect.left);
        const visibleTop = Math.max(0, rect.top);
        const visibleRight = Math.min(rect.right, windowWidth);
        const visibleBottom = Math.min(rect.bottom, windowHeight);
        const visibleArea = (visibleRight - visibleLeft) * (visibleBottom - visibleTop);
        const visibilityPercentage = elementArea > 0 
            ? Math.round((visibleArea / elementArea) * 10000) / 100 
            : 0;

        // 检查可视性（基于可调阈值）
        const isVisible = Math.max(0, visibilityPercentage) >= visibilityThreshold;

        if (isVisible) {
            visibilityInfo.push({
                element: linkElement,
                index: index,
                commentCount: getCommentCount(postElement),
                visibilityPercentage: visibilityPercentage
            });
        }
    });

    // 无可见元素
    if (visibilityInfo.length === 0) {
        return {
            click_status: false,
            message: `没有符合可视阈值(${visibilityThreshold}%)的元素`,
            index: NO_ELEMENT_INDEX
        };
    }

    // 找到可视区中评论数最大的元素
    const targetInfo = visibilityInfo.sort((a, b) => b.commentCount - a.commentCount)[0];

    // 滚动到目标元素
    targetInfo.element.scrollIntoView({
        behavior: scrollToElementBehavior,
        block: 'center',
        inline: 'center'
    });
    await new Promise(resolve => setTimeout(resolve, scrollWaitTime));

    // 查找可点击目标
    const clickableSelectors = [
        'a[href]', 
        'button:not([disabled])', 
        '[onclick]', 
        '[role="button"]:not([aria-disabled="true"])', 
        '.clickable', 
        '.btn:not([disabled])'
    ];

