    const originalBorder = clickTarget.style.border;
    const originalBoxShadow = clickTarget.style.boxShadow;
    const originalTransition = clickTarget.style.transition;

    // 执行点击
    const rect = clickTarget.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;

    const createEvent = (type) => new MouseEvent(type, {
        bubbles: true,
        cancelable: true,
        view: window,
        clientX: centerX,
        clientY: centerY,
        button: 0,
        buttons: 1
    });

    const events = ['mouseover', 'mousemove', 'mousedown', 'mouseup', 'click']
        .map(type => createEvent(type));

    let isClickSuccessful = false;
    const originalDispatch = clickTarget.dispatchEvent;
    clickTarget.dispatchEvent = function(event) {
        const result = originalDispatch.call(this, event);
        if (event.type === 'click') isClickSuccessful = result;
        return result;
    };

