    for (const [i, event] of events.entries()) {
        clickTarget.dispatchEvent(event);
        if (i < events.length - 1) {
            await new Promise(resolve => setTimeout(resolve, Math.floor(Math.random() * 50) + 30));
        }
    }
    clickTarget.dispatchEvent = originalDispatch;

    // 备选点击方式
    if (typeof clickTarget.onclick === 'function') {
        try {
            clickTarget.onclick();
            isClickSuccessful = true;
        } catch (e) { /* 忽略点击异常 */ }
    }

    // 显示橙色提示边框
    if (enableClickIndicator && isClickSuccessful) {
        clickTarget.style.transition = 'all 0.2s ease-in-out';
        clickTarget.style.border = '4px solid #ff7a00'; // 橙色边框
        clickTarget.style.boxShadow = '0 0 0 2px rgba(255, 122, 0, 0.3)'; // 橙色阴影
        await new Promise(resolve => setTimeout(resolve, indicatorDisplayTime));
        // 恢复原始样式
        clickTarget.style.border = originalBorder;
        clickTarget.style.boxShadow = originalBoxShadow;
        clickTarget.style.transition = originalTransition;
    }

    return {
        click_status: isClickSuccessful,
        message: isClickSuccessful 
            ? `已点击可视区最大评论数元素(索引: ${targetInfo.index}, 评论数: ${targetInfo.commentCount}, 可见度: ${targetInfo.visibilityPercentage}%)` 
            : `点击失败(索引: ${targetInfo.index})`,
        index: targetInfo.index,
        maxCommentCount: targetInfo.commentCount,
        visibilityThreshold: visibilityThreshold
    };

} catch (error) {
    return {
        click_status: false,
        message: `操作失败: ${error.message}`,
        index: NO_ELEMENT_INDEX
    };
}

