    const config = {
        targetIndex: 1,
        parentSelector: 'div[role="dialog"] div[class^="html-div"] > * > div[data-visualcompletion="ignore-dynamic"] > div > div:nth-of-type(1)',
        basePosition: 'center',
        randomRange: 50,
        smoothness: 800,
        stepMin: 10,
        stepMax: 25
    };

    try {
        // 参数验证
        const targetIndex = parseInt(config.targetIndex, 10);
        if (isNaN(targetIndex) || targetIndex < 1) throw new Error(`无效索引: ${config.targetIndex}`);

        const validPositions = ['top', 'center', 'bottom'];
        if (!validPositions.includes(config.basePosition)) throw new Error(`无效位置: ${config.basePosition}`);

        // 等待元素加载
        async function waitForElements(selector, timeout = 15000) {
            const start = Date.now();
            while (Date.now() - start < timeout) {
                const elements = Array.from(document.querySelectorAll(selector));
                if (elements.length) return elements;
                window.scrollBy(0, 10); // 触发懒加载
                await new Promise(r => setTimeout(r, 300));
            }
            throw new Error(`未找到元素: ${selector}`);
        }

        // 获取目标元素
        const items = await waitForElements(config.parentSelector);
        if (targetIndex > items.length) throw new Error(`索引超限，共${items.length}个元素`);
        const target = items[targetIndex - 1];

        // 查找滚动容器
        const getScrollContainer = (el) => {
            let container = el.parentElement;
            while (container && container !== document.body) {
                const { overflowY } = getComputedStyle(container);
                if (overflowY === 'auto' || overflowY === 'scroll') return container;
                container = container.parentElement;
            }
            return window;
        };
        const container = getScrollContainer(target);

        // 计算目标位置
        const rect = target.getBoundingClientRect();
        const cRect = container === window ? { top: 0, height: window.innerHeight } : container.getBoundingClientRect();
        const cTop = container === window ? 0 : cRect.top;
        const scrollTop = container.scrollTop || window.scrollY;

        let basePos;
        switch(config.basePosition) {
            case 'top': basePos = rect.top - cTop + scrollTop; break;
            case 'center': basePos = rect.top - cTop + scrollTop + rect.height/2 - cRect.height/2; break;
            case 'bottom': basePos = rect.bottom - cTop + scrollTop - cRect.height; break;
        }
        const targetPos = basePos + (Math.random() - 0.5) * 2 * config.randomRange;

        // 滚动实现
        const scroll = (pos) => {
            if (container === window) container.scrollTo({ top: pos, behavior: 'smooth' });
            else container.scrollTo({ top: pos, behavior: 'smooth' });
        };

        // 模拟滚轮
        const simulateWheel = (pos) => new Promise(resolve => {
            const start = container.scrollTop || window.scrollY;
            const distance = pos - start;
            const startTime = performance.now();

            const ease = t => -(Math.cos(Math.PI * t) - 1) / 2;
            const animate = (t) => {
                const progress = Math.min((t - startTime)/config.smoothness, 1);
                const current = start + distance * ease(progress);
                const delta = current - (container.scrollTop || window.scrollY);

                if (Math.abs(delta) > 1) {
                    const step = Math.min(Math.max(config.stepMin, Math.random()*config.stepMax), Math.abs(delta));
                    const d = delta > 0 ? step : -step;

                    container.dispatchEvent(new WheelEvent('wheel', { deltaY: d, bubbles: true }));
                    container === window ? window.scrollBy(0, d) : container.scrollTop += d;
                }

                progress < 1 ? requestAnimationFrame(animate) : resolve();
            };
            requestAnimationFrame(animate);
        });

        // 多方法尝试
        try {
            scroll(targetPos);
            await new Promise(r => setTimeout(r, config.smoothness));
        } catch (e) {
            try { await simulateWheel(targetPos); }
            catch (e) { container === window ? window.scrollTo(0, targetPos) : container.scrollTop = targetPos; }
        }

        console.log(`已滚动到第${targetIndex}个元素`);
        return true;

    } catch (e) {
        console.error("滚动失败：", e.message);
        return false;
    }

