        const actualMax = INDEX_RANGE.max !== null 
            ? Math.min(INDEX_RANGE.max, totalCount)  // 使用指定的max但不超过实际总数
            : totalCount;  // 未指定max时使用实际总数

        // 验证范围有效性
        if (actualMin > actualMax) {
            console.log(`指定的范围区间无效（min: ${actualMin}, max: ${actualMax}），返回null`);
            return null;
        }

        const randomIndex = generateRandomIndex(actualMin, actualMax);

