        const validPositions = ['top', 'center', 'bottom'];
        if (!validPositions.includes(config.basePosition)) throw new Error(`无效基础位置: ${config.basePosition}`);

        // 2. 等待元素加载并确保其在DOM中稳定
        async function waitForElements(selector, timeout = 10000) {
            const start = Date.now();
            while (Date.now() - start < timeout) {
                const elements = document.querySelectorAll(selector);
                if (elements.length > 0) {
                    // 确保元素已渲染
                    const firstElement = elements[0];
                    if (firstElement.getBoundingClientRect().height > 0) {
                        return Array.from(elements);
