                                   viewportHeight/2 - config.fixedHeaderHeight/2; 
                    break;
                case 'bottom': 
                    baseScrollTop = window.scrollY + rect.bottom - viewportHeight + 
                                   config.fixedHeaderHeight; 
                    break;
            }

            // 限制滚动范围在有效区域内
            const maxScroll = document.documentElement.scrollHeight - window.innerHeight;
            const targetScrollTop = Math.max(0, Math.min(baseScrollTop + 
                (Math.random() - 0.5) * 2 * config.randomRange, maxScroll));

            return targetScrollTop;
        }

        // 4. 滚动并验证位置
        let targetScrollTop = await calculateTargetScroll();
        await smoothWheelScroll(targetScrollTop, config.smoothness, config.wheelStepMin, config.wheelStepMax);

        // 验证并修正位置
        for (let i = 0; i < config.retryCount; i++) {
            if (!isElementInViewport(targetElement, config.basePosition)) {
                console.log(`位置调整中... (${i+1}/${config.retryCount})`);
                targetScrollTop = await calculateTargetScroll();
                await smoothWheelScroll(targetScrollTop, config.smoothness/2, 5, 10);
            } else {
                break;
            }
        }

        console.log(`已滚动到第${targetIndex}个元素`);
        return true;

    } catch (error) {
        console.error("滚动失败：", error.message);
        return false;
    }

    // 检查元素是否在视口中
    function isElementInViewport(el, position) {
        const rect = el.getBoundingClientRect();
        const viewportHeight = window.innerHeight;

        switch(position) {
            case 'top':
                return rect.top >= config.fixedHeaderHeight && 
                       rect.top <= viewportHeight/3;
            case 'center':
                return rect.top + rect.height/2 >= viewportHeight/3 && 
                       rect.top + rect.height/2 <= viewportHeight*2/3;
            case 'bottom':
                return rect.bottom <= viewportHeight && 
                       rect.bottom >= viewportHeight*2/3;
            default:
                return false;
        }
    }

    // 改进的平滑滚动函数
    async function smoothWheelScroll(targetScrollTop, duration, stepMin, stepMax) {
        return new Promise(resolve => {
            const startScrollTop = window.scrollY;
            const distance = targetScrollTop - startScrollTop;
            const startTime = performance.now();

            // 更平滑的缓动函数
            function easeOutCubic(t) { return 1 - Math.pow(1 - t, 3); }

            function animate(currentTime) {
                const elapsed = currentTime - startTime;
                const progress = Math.min(elapsed / duration, 1);
                const easedProgress = easeOutCubic(progress);
                const target = startScrollTop + distance * easedProgress;

                // 直接设置滚动位置而非模拟滚轮，提高精度
                window.scrollTo(0, target);

                if (progress < 1) {
                    requestAnimationFrame(animate);
                } else {
                    // 最终位置微调
                    window.scrollTo(0, targetScrollTop);
                    resolve();
                }
            }

            requestAnimationFrame(animate);
        });
    }

