const browseCountNum = +browse_count;

let minPosition, maxPosition;

if (!browseCountNum || browseCountNum === 0) {
    minPosition = 3;
    maxPosition = 5;
} else {
    minPosition = browseCountNum - 2;
    maxPosition = browseCountNum + 2;
}

minPosition = Math.max(1, minPosition);
maxPosition = Math.min(domLength, Math.min(6, maxPosition));

if (minPosition > maxPosition) {
    minPosition = Math.max(1, 3);
    maxPosition = Math.min(domLength, Math.min(6, 5));
    if (minPosition > maxPosition) {
        minPosition = 1;
        maxPosition = Math.min(domLength, 6);
    }
}

const randomPosition = Math.floor(Math.random() * (maxPosition - minPosition + 1)) + minPosition;
const randomIndex = randomPosition;

const count = Math.min(randomIndex, domLength);
